patterns.template:
// Instead of multiple setState calls:
// setLoading(true); setError(null); setData(null);

// Use useReducer for related state transitions:
type State = { data: T | null; loading: boolean; error: Error | null };
type Action =
  | { type: 'FETCH_START' }
  | { type: 'FETCH_SUCCESS'; data: T }
  | { type: 'FETCH_ERROR'; error: Error };

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'FETCH_START': return { data: null, loading: true, error: null };
    case 'FETCH_SUCCESS': return { data: action.data, loading: false, error: null };
    case 'FETCH_ERROR': return { data: null, loading: false, error: action.error };
  }
}

const [state, dispatch] = useReducer(reducer, { data: null, loading: false, error: null });

// Stable callback reference to prevent child re-renders:
const handleClick = useCallback((id: string) => {
  // Use functional updater to avoid deps on state:
  setItems(prev => prev.filter(item => item.id !== id));
}, []); // Empty deps because functional updater doesn't need current state

// When you DO need external values:
const handleSubmit = useCallback(() => {
  submitForm(formData);
}, [formData]); // formData in deps

// Good: expensive computation that depends on data
const sortedItems = useMemo(
  () => items.slice().sort((a, b) => a.name.localeCompare(b.name)),
  [items]
);

// Good: object/array passed to child component (stable reference)
const contextValue = useMemo(
  () => ({ user, settings, theme }),
  [user, settings, theme]
);

// BAD: simple value derivation (no memoization needed)
// const fullName = useMemo(() => `${first} ${last}`, [first, last]);
// Just use: const fullName = `${first} ${last}`;

// 1. DOM reference
const inputRef = useRef<HTMLInputElement>(null);
useEffect(() => { inputRef.current?.focus(); }, []);

// 2. Mutable value (no re-render on change)
const renderCount = useRef(0);
useEffect(() => { renderCount.current += 1; });

// 3. Previous value tracking
function usePrevious<T>(value: T): T | undefined {
  const ref = useRef<T>();
  useEffect(() => { ref.current = value; });
  return ref.current;
}

// 4. Latest callback ref (avoid stale closures in intervals)
const callbackRef = useRef(callback);
useLayoutEffect(() => { callbackRef.current = callback; });

function useDataFetch<T>(url: string) {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  useEffect(() => {
    const controller = new AbortController();
    setLoading(true);
    setError(null);

    fetch(url, { signal: controller.signal })
      .then(res => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then(setData)
      .catch(err => {
        if (err.name !== 'AbortError') setError(err);
      })
      .finally(() => setLoading(false));

    return () => controller.abort();
  }, [url]);

  return { data, loading, error };
}

function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebouncedValue(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);

  return debouncedValue;
}

// Usage:
const [search, setSearch] = useState('');
const debouncedSearch = useDebounce(search, 300);

useEffect(() => {
  if (debouncedSearch) fetchResults(debouncedSearch);
}, [debouncedSearch]);

function useLocalStorage<T>(key: string, initialValue: T): [T, (value: T | ((prev: T) => T)) => void] {
  const [storedValue, setStoredValue] = useState<T>(() => {
    if (typeof window === 'undefined') return initialValue;
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch {
      return initialValue;
    }
  });

  const setValue = useCallback((value: T | ((prev: T) => T)) => {
    setStoredValue(prev => {
      const newValue = value instanceof Function ? value(prev) : value;
      try {
        window.localStorage.setItem(key, JSON.stringify(newValue));
      } catch (e) {
        console.warn(`Failed to save ${key} to localStorage`, e);
      }
      return newValue;
    });
  }, [key]);

  return [storedValue, setValue];
}

function useMediaQuery(query: string): boolean {
  const [matches, setMatches] = useState(false);

  useEffect(() => {
    const media = window.matchMedia(query);
    setMatches(media.matches);

    const listener = (e: MediaQueryListEvent) => setMatches(e.matches);
    media.addEventListener('change', listener);
    return () => media.removeEventListener('change', listener);
  }, [query]);

  return matches;
}

// Usage:
const isMobile = useMediaQuery('(max-width: 768px)');
const prefersDark = useMediaQuery('(prefers-color-scheme: dark)');
